// ─── JADWAL TAB (SKELETON & PAGINATION LOAD MORE) ────────────────────────────
class JadwalTab extends StatelessWidget {
  const JadwalTab({super.key});

  @override
  Widget build(BuildContext context) {
    context.read<SesiBloc>().add(LoadSesiList());

    return Scaffold(
      appBar: AppBar(
        title: Text(
          'Jadwal Latihan',
          style: TextStyle(fontWeight: FontWeight.w900, fontSize: 20),
        ),
      ),
      body: BlocBuilder<SesiBloc, SesiState>(
        builder: (context, state) {
          if (state is SesiLoading) {
            return SingleChildScrollView(
              child: ListSkeletonWidget(itemCount: 5),
            );
          } else if (state is SesiLoaded) {
            if (state.list.isEmpty) {
              return Center(child: Text('Tidak ada jadwal latihan terdaftar.'));
            }
            return ListView.builder(
              padding: const EdgeInsets.all(20),
              itemCount: state.list.length + (state.hasMore ? 1 : 0),
              itemBuilder: (context, index) {
                if (index == state.list.length) {
                  // Paging Load More button at bottom
                  return Padding(
                    padding: const EdgeInsets.symmetric(vertical: 8),
                    child: ElevatedButton(
                      onPressed: () {
                        context.read<SesiBloc>().add(LoadSesiList(loadMore: true));
                      },
                      style: ElevatedButton.styleFrom(
                        backgroundColor: BrandColors.hijauSoft,
                        foregroundColor: BrandColors.hijau,
                        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                        padding: const EdgeInsets.symmetric(vertical: 14),
                      ),
                      child: Text(
                        'Muat Lebih Banyak...',
                        style: TextStyle(fontWeight: FontWeight.bold),
                      ),
                    ),
                  );
                }

                final sesi = state.list[index];
                return GestureDetector(
                  onTap: () {
                    Navigator.pushNamed(context, '/sesi_detail', arguments: sesi);
                  },
                  child: Card(
                    elevation: 2,
                    shadowColor: Colors.black12,
                    margin: const EdgeInsets.only(bottom: 16),
