  Widget _buildDetailRow(IconData icon, String text) {
    return Row(
      children: [
        Icon(icon, size: 14, color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3)),
        SizedBox(width: 8),
