        title,
        style: TextStyle(
          fontSize: 10,
          fontWeight: FontWeight.bold,
          color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3),
          letterSpacing: 0.8,
        ),
      ),
    );
  }

  Widget _buildRow(String label, String value, {bool isGreenText = false}) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        Text(label, style: TextStyle(color: (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2), fontSize: 13)),
        Text(
          value,
          style: TextStyle(
            fontWeight: FontWeight.bold,
            color: isGreenText ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.text1Dark : BrandColors.text1),
            fontSize: 13.5,
          ),
