class NafasTab extends StatefulWidget {
  const NafasTab({super.key});

  @override
  State<NafasTab> createState() => _NafasTabState();
}

class _NafasTabState extends State<NafasTab> with SingleTickerProviderStateMixin {
  // Mode Tab selector: 'latihan' or 'riwayat'
  String _activeTab = 'latihan';

  // Technique: 'iso' (Sama Kaki), 'equi' (Sama Sisi), 'square' (Segi Empat)
  String _type = 'iso';

  // Step durations in seconds
  int _tarikM = 0, _tarikS = 10;
  int _tahanM = 0, _tahanS = 30;
  int _keluarM = 0, _keluarS = 10;
  int _tahan2M = 0, _tahan2S = 10;

  // Total session duration
  int _totalM = 10, _totalS = 0;

  // Timer & state
  bool _isRunning = false;
  bool _isPaused = false;
  bool _isFinished = false;

  Timer? _timer;
  int _elapsedSec = 0;
  int _currentStepIndex = 0;
  int _stepElapsedSec = 0;
  int _currentCycle = 1;

  AnimationController? _animController;

  // History list
  final List<Map<String, dynamic>> _historyList = [
    {
      'id': 'hist-1',
      'teknik': 'Sama Kaki',
      'durasi_fmt': '10:00',
      'durasi_detik': 600,
      'siklus': 12,
      'timestamp': DateTime.now().subtract(const Duration(hours: 3)),
      'status': 'Selesai',
    },
    {
      'id': 'hist-2',
      'teknik': 'Sama Sisi',
      'durasi_fmt': '05:00',
      'durasi_detik': 300,
      'siklus': 10,
      'timestamp': DateTime.now().subtract(const Duration(days: 1, hours: 2)),
      'status': 'Selesai',
    },
  ];

  @override
  void initState() {
    super.initState();
    _animController = AnimationController(
      vsync: this,
      duration: const Duration(seconds: 1),
    )..repeat();
    _fetchRemoteHistory();
  }

  @override
  void dispose() {
    _timer?.cancel();
    _animController?.dispose();
    super.dispose();
  }

  int get _tarikDur => _tarikM * 60 + _tarikS;
  int get _tahanDur => _tahanM * 60 + _tahanS;
  int get _keluarDur => _keluarM * 60 + _keluarS;
  int get _tahan2Dur => _tahan2M * 60 + _tahan2S;
  int get _totalDur => _totalM * 60 + _totalS;

  List<Map<String, dynamic>> get _steps {
    final tarik = {'key': 'tarik', 'name': 'Tarik', 'full': 'Tarik Nafas', 'voice': 'Satu. Tarik.', 'color': const Color(0xFF0091EA), 'dur': _tarikDur};
    final tahan = {'key': 'tahan', 'name': 'Tahan & Tekan', 'full': 'Tahan dan Tekan', 'voice': 'Dua. Tahan dan tekan.', 'color': const Color(0xFFE8B923), 'dur': _tahanDur};
    final keluar = {'key': 'keluar', 'name': 'Keluarkan', 'full': 'Keluarkan', 'voice': 'Tiga. Keluarkan.', 'color': const Color(0xFF2E8B3D), 'dur': _keluarDur};
    final tahan2 = {'key': 'tahan2', 'name': 'Tahan', 'full': 'Tahan Nafas', 'voice': 'Empat. Tahan.', 'color': const Color(0xFFC9701A), 'dur': _tahan2Dur};

    if (_type == 'square') {
      return [tarik, tahan, keluar, tahan2];
    }
    return [tarik, tahan, keluar];
  }

  int get _cycleDur => _steps.fold(0, (sum, step) => sum + (step['dur'] as int));

  bool get _isValidDuration {
    final cyc = _cycleDur;
    final total = _totalDur;
    return cyc > 0 && total >= cyc && (total % cyc == 0);
  }

  int get _totalCycles => _cycleDur > 0 ? (_totalDur ~/ _cycleDur) : 0;

  void _applyType(String newType) {
    setState(() {
      _type = newType;
      if (newType == 'equi') {
        _tarikM = 0; _tarikS = 10;
        _tahanM = 0; _tahanS = 10;
        _keluarM = 0; _keluarS = 10;
      } else if (newType == 'square') {
        _tarikM = 0; _tarikS = 10;
        _tahanM = 0; _tahanS = 10;
        _keluarM = 0; _keluarS = 10;
        _tahan2M = 0; _tahan2S = 10;
      } else {
        _tarikM = 0; _tarikS = 10;
        _tahanM = 0; _tahanS = 30;
        _keluarM = 0; _keluarS = 10;
      }

      int cycNow = newType == 'square' ? 40 : (newType == 'iso' ? 50 : 30);
      int mult = (600 / cycNow).round();
      if (mult < 1) mult = 1;
      int validTotal = mult * cycNow;
      _totalM = validTotal ~/ 60;
      _totalS = validTotal % 60;
    });
  }

  void _handleStepInput(String stepKey, bool isMin, int delta) {
    setState(() {
      if (stepKey == 'tarik') {
        if (isMin) _tarikM = (_tarikM + delta).clamp(0, 59);
        else _tarikS = (_tarikS + delta).clamp(0, 59);
      } else if (stepKey == 'tahan') {
        if (isMin) _tahanM = (_tahanM + delta).clamp(0, 59);
        else _tahanS = (_tahanS + delta).clamp(0, 59);
      } else if (stepKey == 'keluar') {
        if (isMin) _keluarM = (_keluarM + delta).clamp(0, 59);
        else _keluarS = (_keluarS + delta).clamp(0, 59);
      } else if (stepKey == 'tahan2') {
        if (isMin) _tahan2M = (_tahan2M + delta).clamp(0, 59);
        else _tahan2S = (_tahan2S + delta).clamp(0, 59);
      }

      if (_type == 'equi' || _type == 'square') {
        int mVal = stepKey == 'tarik' ? _tarikM : (stepKey == 'tahan' ? _tahanM : (stepKey == 'keluar' ? _keluarM : _tahan2M));
        int sVal = stepKey == 'tarik' ? _tarikS : (stepKey == 'tahan' ? _tahanS : (stepKey == 'keluar' ? _keluarS : _tahan2S));
        _tarikM = mVal; _tarikS = sVal;
        _tahanM = mVal; _tahanS = sVal;
        _keluarM = mVal; _keluarS = sVal;
        _tahan2M = mVal; _tahan2S = sVal;
      } else if (_type == 'iso' && (stepKey == 'tarik' || stepKey == 'keluar')) {
        int mVal = stepKey == 'tarik' ? _tarikM : _keluarM;
        int sVal = stepKey == 'tarik' ? _tarikS : _keluarS;
        _tarikM = mVal; _tarikS = sVal;
        _keluarM = mVal; _keluarS = sVal;
      }
    });
  }

  void _handleTotalInput(bool isMin, int delta) {
    setState(() {
      if (isMin) _totalM = (_totalM + delta).clamp(0, 120);
      else _totalS = (_totalS + delta).clamp(0, 59);
    });
  }

  void _startSession() {
    if (!_isValidDuration) return;
    setState(() {
      _isRunning = true;
      _isPaused = false;
      _isFinished = false;
      _elapsedSec = 0;
      _currentCycle = 1;
      _currentStepIndex = 0;
      _stepElapsedSec = 0;
    });

    _timer?.cancel();
    _timer = Timer.periodic(const Duration(seconds: 1), (t) => _tick());
  }

  void _tick() {
    if (_isPaused || !_isRunning) return;

    setState(() {
      _elapsedSec++;
      _stepElapsedSec++;

      if (_elapsedSec >= _totalDur) {
        _finishSession();
        return;
      }

      final currentStepDur = _steps[_currentStepIndex]['dur'] as int;
      if (_stepElapsedSec >= currentStepDur) {
        _stepElapsedSec = 0;
        _currentStepIndex++;
        if (_currentStepIndex >= _steps.length) {
          _currentStepIndex = 0;
          _currentCycle++;
        }
      }
    });
  }

  void _pauseSession() {
    setState(() {
      _isPaused = !_isPaused;
    });
  }

  void _resetSession() {
    _timer?.cancel();
    setState(() {
      _isRunning = false;
      _isPaused = false;
      _isFinished = false;
      _elapsedSec = 0;
      _stepElapsedSec = 0;
      _currentCycle = 1;
      _currentStepIndex = 0;
    });
  }

  Future<void> _fetchRemoteHistory() async {
    final endpoints = [
      'http://localhost:8080/api/v1/nafas/history',
      'http://10.0.2.2:8080/api/v1/nafas/history',
    ];

    for (final url in endpoints) {
      try {
        final res = await http.get(Uri.parse(url)).timeout(const Duration(seconds: 2));
        if (res.statusCode == 200) {
          final body = jsonDecode(res.body);
          final data = body['data'] as List?;
          if (data != null && data.isNotEmpty) {
            final List<Map<String, dynamic>> remoteList = [];
            for (final item in data) {
              remoteList.add({
                'id': item['id'] ?? 'hist-${DateTime.now().millisecondsSinceEpoch}',
                'teknik': item['teknik'] ?? 'Sama Kaki',
                'durasi_fmt': item['durasi_fmt'] ?? '10:00',
                'durasi_detik': item['durasi_detik'] ?? 600,
                'siklus': item['siklus'] ?? 12,
                'timestamp': item['timestamp'] != null ? (DateTime.tryParse(item['timestamp'].toString()) ?? DateTime.now()) : DateTime.now(),
                'status': 'Selesai',
              });
            }
            if (mounted) {
              setState(() {
                _historyList.clear();
                _historyList.addAll(remoteList);
              });
            }
            break;
          }
        }
      } catch (_) {}
    }
  }

  void _finishSession() {
    _timer?.cancel();
    final techniqueLabel = _type == 'square' ? 'Segi Empat' : (_type == 'equi' ? 'Sama Sisi' : 'Sama Kaki');
    final record = {
      'id': 'hist-${DateTime.now().millisecondsSinceEpoch}',
      'teknik': techniqueLabel,
      'durasi_fmt': _fmt(_totalDur),
      'durasi_detik': _totalDur,
      'siklus': _totalCycles,
      'timestamp': DateTime.now(),
      'status': 'Selesai',
    };

    setState(() {
      _isRunning = false;
      _isPaused = false;
      _isFinished = true;
      _historyList.insert(0, record);
    });

    final payload = jsonEncode({
      'anggota_id': 'a0000001-0000-0000-0000-000000000001',
      'anggota_nama': 'Ahmad Santoso',
      'cabang_nama': 'Kota Yogyakarta',
      'unit_nama': 'Malioboro',
      'teknik': techniqueLabel,
      'durasi_detik': _totalDur,
      'durasi_fmt': _fmt(_totalDur),
      'siklus': _totalCycles,
    });

    // Post to backend API asynchronously (supports both localhost and Android Emulator 10.0.2.2)
    Future.microtask(() async {
      final endpoints = [
        'http://localhost:8080/api/v1/nafas/history',
        'http://10.0.2.2:8080/api/v1/nafas/history',
      ];
      for (final url in endpoints) {
        try {
          final res = await http.post(
            Uri.parse(url),
            headers: {'Content-Type': 'application/json'},
            body: payload,
          ).timeout(const Duration(seconds: 3));
          if (res.statusCode == 200 || res.statusCode == 201) break;
        } catch (_) {}
      }
    });
  }

  String _fmt(int sec) {
    int m = sec ~/ 60;
    int s = sec % 60;
    return '${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}';
  }

  @override
  Widget build(BuildContext context) {
    return SingleChildScrollView(
      child: Column(
        children: [
          // Hero Header Banner
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 24),
            decoration: BoxDecoration(
              gradient: LinearGradient(
                colors: [Color(0xFF0072B8), Color(0xFF0091EA)],
                begin: Alignment.topLeft,
                end: Alignment.bottomRight,
              ),
              borderRadius: BorderRadius.only(
                bottomLeft: Radius.circular(24),
                bottomRight: Radius.circular(24),
              ),
            ),
            child: Row(
              children: [
                Container(
                  width: 48,
                  height: 48,
                  decoration: BoxDecoration(color: (themeNotifier.isDarkMode ? BrandColors.cardDark : Colors.white),
                    shape: BoxShape.circle,
                    boxShadow: [
                      BoxShadow(color: Colors.black.withOpacity(0.2), blurRadius: 8, offset: const Offset(0, 2)),
                    ],
                  ),
                  child: Icon(Icons.air, color: Color(0xFF0072B8), size: 28),
                ),
                SizedBox(width: 16),
                Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        'SATRIA NUSANTARA',
                        style: TextStyle(color: Colors.white70, fontSize: 11, fontWeight: FontWeight.bold, letterSpacing: 1.2),
                      ),
                      SizedBox(height: 2),
                      Text(
                        'Nafas Buka Tutup',
                        style: TextStyle(color: Colors.white, fontSize: 20, fontWeight: FontWeight.bold),
                      ),
                      SizedBox(height: 2),
                      Text(
                        'Modul Olah Nafas & Energi Diri',
                        style: TextStyle(color: Colors.white70, fontSize: 12),
                      ),
                    ],
                  ),
                ),
              ],
            ),
          ),

          // Sub-Tab Switcher (Latihan vs Riwayat)
          if (!_isRunning && !_isFinished)
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 16, 16, 0),
              child: Row(
                children: [
                  Expanded(
                    child: InkWell(
                      onTap: () => setState(() => _activeTab = 'latihan'),
                      borderRadius: BorderRadius.circular(10),
                      child: Container(
                        padding: const EdgeInsets.symmetric(vertical: 10),
                        decoration: BoxDecoration(
                          color: _activeTab == 'latihan' ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.borderDark : Colors.grey[200]),
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: Center(
                          child: Text(
                            'LATIHAN PERNAFASAN',
                            style: TextStyle(
                              fontWeight: FontWeight.bold,
                              fontSize: 12,
                              color: _activeTab == 'latihan' ? Colors.white : (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2),
                            ),
                          ),
                        ),
                      ),
                    ),
                  ),
                  SizedBox(width: 10),
                  Expanded(
                    child: InkWell(
                      onTap: () {
                        setState(() => _activeTab = 'riwayat');
                        _fetchRemoteHistory();
                      },
                      borderRadius: BorderRadius.circular(10),
                      child: Container(
                        padding: const EdgeInsets.symmetric(vertical: 10),
                        decoration: BoxDecoration(
                          color: _activeTab == 'riwayat' ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.borderDark : Colors.grey[200]),
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: Center(
                          child: Text(
                            'RIWAYAT (${_historyList.length})',
                            style: TextStyle(
                              fontWeight: FontWeight.bold,
                              fontSize: 12,
                              color: _activeTab == 'riwayat' ? Colors.white : (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2),
                            ),
                          ),
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),

          Padding(
            padding: const EdgeInsets.all(16.0),
            child: _isRunning
                ? _buildSessionView()
                : (_isFinished
                    ? _buildFinishedView()
                    : (_activeTab == 'riwayat' ? _buildHistoryView() : _buildSetupView())),
          ),
        ],
      ),
    );
  }

  Widget _buildHistoryView() {
    int totalSec = _historyList.fold(0, (sum, item) => sum + (item['durasi_detik'] as int));
    int totalMin = totalSec ~/ 60;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // Summary Cards
        Row(
          children: [
            Expanded(
              child: Container(
                padding: const EdgeInsets.all(14),
                decoration: BoxDecoration(color: (themeNotifier.isDarkMode ? BrandColors.cardDark : Colors.white),
                  borderRadius: BorderRadius.circular(14),
                  border: Border.all(color: (themeNotifier.isDarkMode ? BrandColors.borderDark : BrandColors.border)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Total Sesi', style: TextStyle(fontSize: 11, color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3))),
                    SizedBox(height: 4),
                    Text('${_historyList.length} Sesi', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold, color: BrandColors.hijau)),
                  ],
                ),
              ),
            ),
            SizedBox(width: 10),
            Expanded(
              child: Container(
                padding: const EdgeInsets.all(14),
                decoration: BoxDecoration(color: (themeNotifier.isDarkMode ? BrandColors.cardDark : Colors.white),
                  borderRadius: BorderRadius.circular(14),
                  border: Border.all(color: (themeNotifier.isDarkMode ? BrandColors.borderDark : BrandColors.border)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Total Durasi', style: TextStyle(fontSize: 11, color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3))),
                    SizedBox(height: 4),
                    Text('$totalMin Menit', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold, color: BrandColors.biru)),
                  ],
                ),
              ),
            ),
          ],
        ),
        SizedBox(height: 16),

        Text(
          'CATATAN RIWAYAT LATIHAN',
          style: TextStyle(fontSize: 12, fontWeight: FontWeight.bold, color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3), letterSpacing: 0.5),
        ),
        SizedBox(height: 10),

        if (_historyList.isEmpty)
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(24),
            decoration: BoxDecoration(color: (themeNotifier.isDarkMode ? BrandColors.cardDark : Colors.white),
              borderRadius: BorderRadius.circular(14),
              border: Border.all(color: (themeNotifier.isDarkMode ? BrandColors.borderDark : BrandColors.border)),
            ),
            child: Column(
              children: [
                Icon(Icons.history_toggle_off, size: 48, color: (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3)),
                SizedBox(height: 8),
                Text('Belum ada riwayat latihan', style: TextStyle(color: (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2), fontSize: 13)),
              ],
            ),
          )
        else
          ListView.separated(
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            itemCount: _historyList.length,
            separatorBuilder: (_, __) => SizedBox(height: 10),
            itemBuilder: (context, index) {
              final item = _historyList[index];
              final DateTime dt = item['timestamp'] as DateTime;
              final dateStr = '${dt.day}/${dt.month}/${dt.year} • ${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}';
              final String teknik = item['teknik'] as String;

              Color badgeColor = const Color(0xFF0091EA);
              if (teknik == 'Sama Kaki') badgeColor = BrandColors.hijau;
              else if (teknik == 'Segi Empat') badgeColor = Colors.orange;

