// ─── NAFAS GEOMETRIC VISUALIZER PAINTER ──────────────────────────────────────

class NafasVisualizerPainter extends CustomPainter {
  final String type;
  final int stepIndex;
  final double stepProgress;
  final Color phaseColor;

  NafasVisualizerPainter({
    required this.type,
    required this.stepIndex,
    required this.stepProgress,
    required this.phaseColor,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final double w = size.width;
    final double h = size.height;

    final Paint outlinePaint = Paint()
      ..color = (themeNotifier.isDarkMode ? BrandColors.borderDark : Colors.grey[300])!
      ..style = PaintingStyle.stroke
      ..strokeWidth = 3.0;

    final Paint activeLinePaint = Paint()
      ..color = phaseColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = 5.0
      ..strokeCap = StrokeCap.round;

    final List<Offset> points = [];

    if (type == 'square') {
      double marginX = w * 0.22;
      double marginY = h * 0.18;
      points.add(Offset(marginX, h - marginY));
      points.add(Offset(marginX, marginY));
      points.add(Offset(w - marginX, marginY));
      points.add(Offset(w - marginX, h - marginY));
    } else if (type == 'equi') {
      points.add(Offset(w * 0.18, h * 0.82));
      points.add(Offset(w * 0.50, h * 0.18));
      points.add(Offset(w * 0.82, h * 0.82));
    } else {
      points.add(Offset(w * 0.50, h * 0.28));
      points.add(Offset(w * 0.84, h * 0.72));
      points.add(Offset(w * 0.16, h * 0.72));
    }

    final Path path = Path();
    path.moveTo(points[0].dx, points[0].dy);
    for (int i = 1; i < points.length; i++) {
      path.lineTo(points[i].dx, points[i].dy);
    }
    path.close();
    canvas.drawPath(path, outlinePaint);

    int numPoints = points.length;
    int currentPIndex = stepIndex % numPoints;
    int nextPIndex = (stepIndex + 1) % numPoints;

    Offset startP = points[currentPIndex];
    Offset endP = points[nextPIndex];

    Offset currentMarkerPos = Offset(
      startP.dx + (endP.dx - startP.dx) * stepProgress,
      startP.dy + (endP.dy - startP.dy) * stepProgress,
    );

    final Path activePath = Path();
    activePath.moveTo(startP.dx, startP.dy);
    activePath.lineTo(currentMarkerPos.dx, currentMarkerPos.dy);
    canvas.drawPath(activePath, activeLinePaint);

    for (int i = 0; i < points.length; i++) {
      final isStart = i == 0;
      final Paint nodePaint = Paint()
        ..color = isStart ? Colors.redAccent : (themeNotifier.isDarkMode ? BrandColors.text3Dark : Colors.grey[400])!
        ..style = PaintingStyle.fill;
      canvas.drawCircle(points[i], isStart ? 6 : 4, nodePaint);
    }

    final Paint glowPaint = Paint()
      ..color = phaseColor.withOpacity(0.35)
      ..style = PaintingStyle.fill;
    canvas.drawCircle(currentMarkerPos, 16, glowPaint);

    final Paint markerPaint = Paint()
      ..color = phaseColor
      ..style = PaintingStyle.fill;
    canvas.drawCircle(currentMarkerPos, 8, markerPaint);

    final Paint corePaint = Paint()
      ..color = Colors.white
      ..style = PaintingStyle.fill;
    canvas.drawCircle(currentMarkerPos, 3, corePaint);
  }

  @override
  bool shouldRepaint(covariant NafasVisualizerPainter oldDelegate) {
    return oldDelegate.stepProgress != stepProgress ||
        oldDelegate.stepIndex != stepIndex ||
        oldDelegate.type != type ||
        oldDelegate.phaseColor != phaseColor;
  }
}

// ─── KEBUGARAN SCORING INPUT SCREEN (LEADING BACK ACTION) ─────────────────────
class KebugaranScoringScreen extends StatefulWidget {
  const KebugaranScoringScreen({super.key});

  @override
  State<KebugaranScoringScreen> createState() => _KebugaranScoringScreenState();
}

class _KebugaranScoringScreenState extends State<KebugaranScoringScreen> {
  final TextEditingController _nafasController = TextEditingController(text: '45');
  final TextEditingController _pushupsController = TextEditingController(text: '35');
  final TextEditingController _situpsController = TextEditingController(text: '30');
  final TextEditingController _flexibilityController = TextEditingController(text: '15');
  final TextEditingController _shuttleRunController = TextEditingController(text: '11.5');
  bool _isSubmitting = false;

  String _calculateCategory() {
    int nafas = int.tryParse(_nafasController.text) ?? 0;
    int pushup = int.tryParse(_pushupsController.text) ?? 0;

    if (nafas >= 40 && pushup >= 30) return 'Sangat Baik';
    if (nafas >= 25 && pushup >= 20) return 'Baik';
    return 'Cukup';
  }

  Future<void> _submitScores() async {
    setState(() => _isSubmitting = true);
    try {
      final payload = {
        'nafas_dalam_air': int.tryParse(_nafasController.text) ?? 45,
        'push_up': int.tryParse(_pushupsController.text) ?? 35,
        'sit_up': int.tryParse(_situpsController.text) ?? 30,
        'sit_and_reach': int.tryParse(_flexibilityController.text) ?? 15,
        'shuttle_run': double.tryParse(_shuttleRunController.text) ?? 11.5,
        'kategori_keseluruhan': _calculateCategory(),
      };

      final response = await http.post(
        Uri.parse('http://localhost:8080/api/v1/organization/anggota/a0000001-0000-0000-0000-000000000001/kebugaran'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(payload),
      );

      if (!mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Nilai kebugaran berhasil disimpan! (Kategori: ${_calculateCategory()})'),
          backgroundColor: BrandColors.hijau,
          behavior: SnackBarBehavior.floating,
          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
        ),
      );
      Navigator.pop(context);
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Skor kebugaran berhasil diperbarui secara lokal!'),
          backgroundColor: BrandColors.hijau,
          behavior: SnackBarBehavior.floating,
          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
        ),
      );
      Navigator.pop(context);
    } finally {
      if (mounted) setState(() => _isSubmitting = false);
    }
  }

