class RegisterWizardScreen extends StatefulWidget {
  const RegisterWizardScreen({super.key});

  @override
  State<RegisterWizardScreen> createState() => _RegisterWizardScreenState();
}

class _RegisterWizardScreenState extends State<RegisterWizardScreen> {
  final PageController _pageController = PageController();
  int _currentStep = 0;

  // Google SSO mode flag
  bool _isGoogleMode = false;
  String _googleInitial = '';

  // Step 1 Controllers
  final TextEditingController _emailController = TextEditingController();
  final TextEditingController _passwordController = TextEditingController();
  final TextEditingController _confirmPasswordController = TextEditingController();

  // Step 2 Controllers
  final TextEditingController _nameController = TextEditingController();
  final TextEditingController _phoneController = TextEditingController();
  final TextEditingController _birthDateController = TextEditingController();
  String _gender = 'Pria';
  String _selectedProvince = 'Jawa Barat';
  String _selectedCity = 'Bandung';
  String _selectedTingkat = 'Dasar';
  String _selectedJurus = 'Jurus 5';

  // Step 3 Controllers
  final TextEditingController _searchUnitController = TextEditingController(text: 'Bandung');
  String _selectedUnit = 'Unit Balkot · Sab & Sel 07.00';

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    final args = ModalRoute.of(context)?.settings.arguments as Map?;
    if (args != null && args['email'] != null && !_isGoogleMode) {
      _isGoogleMode = true;
      _emailController.text = args['email'] ?? '';
      _nameController.text = args['name'] ?? '';
      _phoneController.text = args['phone'] ?? '';
      _googleInitial = args['initial'] ?? '';
      // Auto jump to step 2 (Data Diri) since Google handles auth
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (_currentStep == 0) {
          _pageController.jumpToPage(1);
        }
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Daftar Anggota Baru'),
        leading: _currentStep == 3
            ? null
            : IconButton(
                icon: Icon(Icons.arrow_back_ios_new, size: 20),
                onPressed: () {
                  if (_currentStep > 0) {
                    _pageController.previousPage(
                      duration: const Duration(milliseconds: 300),
                      curve: Curves.easeInOut,
                    );
                  } else {
                    Navigator.pop(context);
                  }
                },
              ),
      ),
      body: PageView(
        controller: _pageController,
        physics: const NeverScrollableScrollPhysics(),
        onPageChanged: (page) => setState(() => _currentStep = page),
        children: [
          _buildStep1(),
          _buildStep2(),
          _buildStep3(),
          _buildStep4Waiting(),
        ],
      ),
    );
  }

