            ),
            child: Text('Kembali ke Login', style: TextStyle(fontWeight: FontWeight.bold)),
          ),
        ],
      ),
    );
  }

  Widget _buildProgressBar() {
    return Row(
      children: [
        _buildStepIndicator(1, 'Akun', _currentStep >= 0),
        _buildStepDivider(_currentStep >= 1),
        _buildStepIndicator(2, 'Data diri', _currentStep >= 1),
        _buildStepDivider(_currentStep >= 2),
        _buildStepIndicator(3, 'Unit', _currentStep >= 2),
      ],
    );
  }

  Widget _buildStepIndicator(int stepNum, String label, bool isActive) {
    return Column(
      children: [
        CircleAvatar(
          radius: 16,
          backgroundColor: isActive ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.borderDark : Colors.grey[300]),
          child: _currentStep > stepNum - 1
              ? Icon(Icons.check, size: 14, color: Colors.white)
              : Text(
                  '$stepNum',
                  style: TextStyle(fontSize: 12, color: isActive ? Colors.white : (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3), fontWeight: FontWeight.bold),
                ),
        ),
        SizedBox(height: 4),
        Text(
          label,
          style: TextStyle(
            fontSize: 10,
            fontWeight: isActive ? FontWeight.bold : FontWeight.normal,
            color: isActive ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.text3Dark : BrandColors.text3),
          ),
        ),
      ],
    );
  }

  Widget _buildStepDivider(bool isActive) {
    return Expanded(
      child: Container(
        height: 2,
        color: isActive ? BrandColors.hijau : (themeNotifier.isDarkMode ? BrandColors.borderDark : Colors.grey[300]),
      ),
    );
  }

  Widget _buildUnitDetailRow(String label, String value) {
    return Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        SizedBox(
          width: 60,
          child: Text(
            label,
            style: TextStyle(fontSize: 12, color: (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2), fontWeight: FontWeight.w500),
          ),
        ),
        Expanded(
          child: Text(
            value,
            style: TextStyle(fontSize: 12, color: (themeNotifier.isDarkMode ? BrandColors.text1Dark : BrandColors.text1), fontWeight: FontWeight.bold),
          ),
        ),
      ],
    );
  }

  Widget _buildSummaryRow(String label, String value) {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      children: [
        Text(label, style: TextStyle(fontSize: 12.5, color: (themeNotifier.isDarkMode ? BrandColors.text2Dark : BrandColors.text2))),
        Text(value, style: TextStyle(fontSize: 12.5, fontWeight: FontWeight.bold, color: (themeNotifier.isDarkMode ? BrandColors.text1Dark : BrandColors.text1))),
      ],
    );
  }
}

